bomData.valueScript:
// Type of the Bom-Element (will be checked in order output)
  let elementType='Board';

  // ProductionSite Category (to split the orders for different production sites)
  let elementCategory='';

  // Id of the parent to create the hierarchy
  let parentBomId=part.pa_BomId;

  // Call the function to process the Bom-Element
  GlobalFunc.process_BoardBom(this, part, elementType, elementCategory, parentBomId);

ncData.valueScript:
//====================================================================
  // Get data for drillings and rotation
  //====================================================================

  let drillings: any[] = [];
  let drills: any[] = [];
  let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId);
  let insertPoint = GlobalFunc.process_MachiningInsertionHelper('012',part2.pa_Model3DGroupName)
  if (part2.pa_HardwareIdentifier == 'FrontConnector' || part2.pa_HardwareIdentifier == 'FrontAndCarcaseConnector') {
    processings.forEach((processing) => {
      drills = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Front');
      drills.forEach((drill) => {
        drillings.push(drill);
      });
    });

    //====================================================================
    // For each drilling (insert the drillings)
    //====================================================================

    drillings.forEach(x => {
      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL = "102";

      if (part2.pa_Rotation == 0) {
        DrillVert.nc_XA = posRel.x + insertPoint.InsertionPointX + x.XA;
        DrillVert.nc_YA = partSelf._dimy - (posRel.y + insertPoint.InsertionPointY + x.YA);
      }
      else if (part2.pa_Rotation == 90) {
        DrillVert.nc_XA = posRel.x - insertPoint.InsertionPointY - x.YA;
        DrillVert.nc_YA = partSelf._dimy - (posRel.y + insertPoint.InsertionPointX + x.XA);
      }
      else if (part2.pa_Rotation == 180) {
        DrillVert.nc_XA = posRel.x + part2._dimx - insertPoint.InsertionPointX - x.XA;
        DrillVert.nc_YA = partSelf._dimy - (posRel.y - insertPoint.InsertionPointY - x.YA);
      }
      else if (part2.pa_Rotation == 270) {
        DrillVert.nc_XA = posRel.x + insertPoint.InsertionPointY + x.YA;
        DrillVert.nc_YA = partSelf._dimy - (posRel.y + part2._dimy - insertPoint.InsertionPointX - x.XA);
      }


      DrillVert.nc_TI = x.TI;
      DrillVert.nc_DU = x.DU;

      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";

      // Add drawing
      if (part2.pa_Rotation == 0) {
        let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + insertPoint.InsertionPointX + x.XA, posRel.y + insertPoint.InsertionPointY + x.YA, 0, x.DU, x.DU, x.TI);
        drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');
      }
      else if (part2.pa_Rotation == 90) {
        let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x - insertPoint.InsertionPointY - x.YA, posRel.y + insertPoint.InsertionPointX + x.XA, 0, x.DU, x.DU, x.TI);
        drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');
      }
      else if (part2.pa_Rotation == 180) {
        let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + part2._dimx - insertPoint.InsertionPointX - x.XA, posRel.y - insertPoint.InsertionPointY - x.YA, 0, x.DU, x.DU, x.TI);
        drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');
      }
      else if (part2.pa_Rotation == 270) {
        let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, posRel.x + insertPoint.InsertionPointY + x.YA, posRel.y + part2._dimy - insertPoint.InsertionPointX - x.XA, 0, x.DU, x.DU, x.TI);
        drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');
      }

    });
  }

//====================================================================
  // Get fillerHardwareInfo
  //====================================================================
  interface iFillerLeftHardwareInfo {
    Model3D: string[];
    ProcessingItem: string[];
    PosX: number[];
    PosY: number[];
  }
  let fillerHardwareInfo: iFillerLeftHardwareInfo = JSON.parse(partSelf.pa_HardwareInfo);

  let i: number = 0;
  fillerHardwareInfo.ProcessingItem.forEach(fillerHardware => {
    //====================================================================
    // Get data for drillings and rotation
    //====================================================================

    let drillings: any[] = [];
    let drills: any[] = [];
    let processings = GlobalFunc.find_ProcessingMapping(fillerHardware);
    processings.forEach((processing) => {
      drills = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Front');
      drills.forEach((drill) => {
        drillings.push(drill);
      });
    });
    //====================================================================
    // For each drilling (insert the drillings)
    //====================================================================
    drillings.forEach(x => {
      // Add Vertical Drill
      let DrillVert = this.addncout_DrillVert();
      DrillVert.nc_TOOL = "102";
      DrillVert.nc_XA = fillerHardwareInfo.PosX[i] + x.XA;
      DrillVert.nc_YA = fillerHardwareInfo.PosY[i] + x.YA;
      DrillVert.nc_TI = x.TI;
      DrillVert.nc_DU = x.DU;
      DrillVert.nc_BM = x.matrix_BM || "LS"
      DrillVert.nc_WI = x.matrix_WI ?? 0;
      DrillVert.nc_AB = x.matrix_AB ?? 1;
      DrillVert.nc_LA = x.matrix_LA ?? 0;
      DrillVert.nc_MI = x.matrix_MI ?? 0;
      DrillVert.nc_KO = x.matrix_KO || "00";
      DrillVert.nc_Side = "Top";

      // Add drawing
      let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, fillerHardwareInfo.PosX[i] + x.XA, fillerHardwareInfo.PosY[i] + x.YA, 0, x.DU, x.DU, x.TI);
      drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU / 2 + '" /></svg>', 'z');

    });
    i++
  });
